import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklySummary {
  totalSpent: number;
  weeklyBudget: number;
  remaining: number;
}

interface SpendingByCategory {
  category: string;
  amount: number;
}

interface WeeklySpending {
  day: string;
  spent: number;
}

interface ExpenseData {
  weeklySummary: WeeklySummary;
  spendingByCategory: SpendingByCategory[];
  weeklySpending: WeeklySpending[];
}

export default function Widget() {
  const expenseData = response.data as ExpenseData;
  const { weeklySummary, spendingByCategory, weeklySpending } = expenseData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Weekly Expense
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              ${weeklySummary.totalSpent.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Budget: ${weeklySummary.weeklyBudget.toFixed(2)} | Remaining: ${weeklySummary.remaining.toFixed(2)}
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: weeklySpending.map(d => d.spent),
                color: '#FF5722',
              },
            ]}
            xAxis={[
              {
                data: weeklySpending.map(d => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />

          <Grid container spacing={1}>
            {spendingByCategory.map((category, index) => (
              <Grid item xs={6} key={index}>
                <Chip
                  label={`${category.category}: $${category.amount.toFixed(2)}`}
                  sx={{ width: '100%', fontSize: '10px', bgcolor: '#FFC107', color: '#1F2937' }}
                />
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
